// Unit 12. PC vs imparfait
// The Critical Distinction

import COVERAGE_U12 from './_coverage_u12.js';

export default {n:12,lang:"fr",srcLang:"en",track:"v2",title:"PC vs imparfait",sub:"The Critical Distinction",icon:"⚖️",level:"A2.4",color:"#7B5EE8",lessons:[
  {id:"fre12l1",title:"Les mots-signaux",icon:"🚦",xp:15,board:true,steps:[
        {type:"intro",title:"Signal words for each tense",desc:"Certain words and expressions naturally pair with passé composé or imparfait. Learning to spot these signals makes choosing the right tense much easier.",goals:["Identify PC signal words","Identify imparfait signal words","Choose tenses based on context clues"]},
        {type:"tip",title:"Tense signals",text:"PASSÉ COMPOSÉ signals:\nsoudain (suddenly)\ntout à coup (all of a sudden)\nhier (yesterday)\nlundi dernier (last Monday)\nune fois (once, one time)\n\nIMPARFAIT signals:\ntoujours (always)\nsouvent (often)\nd'habitude (usually)\nchaque jour (every day)\nquand j'étais petit (when I was little)"},
        {type:"teach",trg:"soudain",src:"suddenly",pos:"adv",gender:null,phonetic:"soo-DAN",note:"Signals a sudden event.\nAlmost always followed by passé composé.",example:"A: Qu'est-ce qui s'est passé?\nB: Soudain, il a commencé à pleuvoir.\nA: Et vous étiez dehors?",exampleSrc:"A: What happened?\nB: Suddenly, it started to rain.\nA: And you were outside?",funFact:"Suddenly. Adverb. From Latin 'subitaneus.' Narrative interruption."},
        {type:"teach",trg:"d'habitude",src:"usually",pos:"adv",gender:null,phonetic:"dah-bee-TEWD",note:"Signals habitual action.\nNaturally pairs with imparfait.",example:"A: Tu fais quoi le samedi?\nB: D'habitude, je faisais du sport.\nA: Et maintenant?",exampleSrc:"A: What do you do on Saturdays?\nB: Usually, I used to do sports.\nA: And now?",funFact:"Usually. Literally 'of habit.' Common frequency marker."},
        {type:"teach",trg:"tout à coup",src:"all of a sudden",pos:"intj",gender:null,phonetic:"too tah KOO",note:"Like soudain but more dramatic.\nAlways signals a sudden event (PC).",example:"A: Tout à coup, le chat a sauté sur la table!\nB: Vraiment? Et après?\nA: Il a renversé mon café!",exampleSrc:"A: All of a sudden, the cat jumped on the table!\nB: Really? And then?\nA: He knocked over my coffee!",funFact:"Suddenly. Fixed phrase. Literally 'all at blow.' Narrative interruption marker."},
        {type:"teach",trg:"chaque jour",src:"every day",pos:"intj",gender:null,phonetic:"shahk ZHOOR",note:"Chaque + time = repeated habit.\nSignals imparfait.",example:"A: Tu allais souvent à la plage?\nB: Oui, chaque jour en été!\nA: Quelle chance!",exampleSrc:"A: Did you go to the beach often?\nB: Yes, every day in summer!\nA: How lucky!",funFact:"Every day. Chaque (each) + jour (day). Invariable chaque."},
        {type:"mc",q:"'Soudain, elle ___.' Which tense fits?",opts:["Passé composé","Imparfait","Present","Future"],ans:"Passé composé",hint:"A sudden event needs the completed tense."},
        {type:"fb",opts:["me levais","me suis levé","me lève","me lèverai"],hint:"Usually I used to get up. Habitual = ongoing past.",s:"D'habitude, je {1} à huit heures. (to get up, imparfait)",a:"me levais"},
        {type:"mc",q:"Which word signals imparfait?",opts:["Soudain","Souvent","Hier matin","Une fois"],ans:"Souvent",hint:"Which word suggests something happened regularly, not once?"},
        {type:"fb",opts:["a entendu","entendait","entend","entendra"],hint:"All of a sudden, he heard a noise. Sudden = specific event.",s:"Tout à coup, il {1} un bruit. (to hear, PC)",a:"a entendu"},
        {type:"match",pairs:[{trg:"soudain",src:"→ passé composé"},{trg:"d'habitude",src:"→ imparfait"},{trg:"tout à coup",src:"→ passé composé"},{trg:"chaque été",src:"→ imparfait"}]},
        {type:"mc",q:"'Chaque matin, elle ___ du café.' Which tense?",opts:["Passé composé","Present","Imparfait","Conditional"],ans:"Imparfait",hint:"Every morning = repeated habit in the past."},
        {type:"fb",opts:["faisait","a fait","fait","fera"],hint:"Yesterday it was very cold. Weather description = background.",s:"Hier, il {1} très froid. (to be, imparfait for weather)",a:"faisait"},
        {type:"mc",q:"'Une fois, j'ai vu un ours dans la forêt.' Why passé composé?",opts:["It was habitual","It was ongoing","It was background","It was a one-time specific event"],ans:"It was a one-time specific event",hint:"Une fois (one ___) = single, completed ___."},
        {type:"fb",opts:["Chaque été","Hier","Soudain","Une fois"],hint:"Which expression signals a yearly habit?",s:"{1}, nous allions à la mer. (every summer)",a:"Chaque été"},
        {type:"match",pairs:[{trg:"toujours",src:"→ imparfait"},{trg:"lundi dernier",src:"→ passé composé"},{trg:"souvent",src:"→ imparfait"},{trg:"ce jour-là",src:"→ passé composé"}]},
        {type:"mc",q:"Complete: 'Hier soir, je ___ quand soudain le téléphone ___.'",opts:["lisais / a sonné","ai lu / sonnait","lis / sonne","lirai / sonnera"],ans:"lisais / a sonné",hint:"Background action (reading) interrupted by sudden event (phone)."},
        {type:"fb",opts:["jouais","ai joué","joue","jouerai"],hint:"When I was little, I always used to play. Childhood habit.",s:"Quand j'étais petit, je {1} toujours au parc. (to play)",a:"jouais"}
  ]},
  {id:"fre12l2",title:"Actions ou descriptions?",icon:"🎭",xp:15,board:true,steps:[
        {type:"intro",title:"Actions vs descriptions",desc:"Passé composé tells WHAT HAPPENED (actions). Imparfait tells WHAT THINGS WERE LIKE (descriptions). This lesson drills the distinction between events and states.",goals:["Distinguish events from states","Use PC for completed actions","Use imparfait for descriptions and states"]},
        {type:"tip",title:"Actions vs states",text:"PASSÉ COMPOSÉ = ACTIONS (what happened)\nJ'ai mangé. (I ate.)\nElle est partie. (She left.)\nIl a plu. (It rained.)\n\nIMPARFAIT = STATES (what things were like)\nJ'avais faim. (I was hungry.)\nElle était fatiguée. (She was tired.)\nIl faisait froid. (It was cold.)\n\nStates = être, avoir, feelings, weather, time, age.\nActions = specific things that happened."},
        {type:"teach",trg:"J'avais faim.",src:"I was hungry.",pos:"intj",gender:null,phonetic:"zhah-VAY fan",note:"Avoir faim = to be hungry.\nStates/feelings = imparfait.\nJ'avais = imparfait of avoir.",example:"A: Pourquoi tu as mangé autant?\nB: J'avais très faim!\nA: Tu n'avais pas déjeuné?",exampleSrc:"A: Why did you eat so much?\nB: I was very hungry!\nA: You hadn't had lunch?",funFact:"I was hungry. Reinforces imperfect + hunger pattern."},
        {type:"teach",trg:"Elle était fatiguée.",src:"She was tired.",pos:"verb",gender:null,phonetic:"el ay-TAY fah-tee-GAY",note:"Describing a state = imparfait.\nÉtait = imparfait of être.\nFatiguée: extra -e for feminine.",example:"A: Marie est sortie hier soir?\nB: Non, elle était fatiguée.\nA: Elle travaille trop!",exampleSrc:"A: Did Marie go out last night?\nB: No, she was tired.\nA: She works too much!",funFact:"She was tired. Imperfect + feminine agreement. State not event."},
        {type:"teach",trg:"Il a commencé à pleuvoir.",src:"It started to rain.",pos:"verb",gender:null,phonetic:"eel ah koh-mahn-SAY ah pluh-VWAR",note:"Starting/stopping = an event.\nEvents use passé composé.\nCommencer à + infinitif.",example:"A: Il faisait beau ce matin.\nB: Oui, mais il a commencé à pleuvoir à midi.\nA: C'est dommage!",exampleSrc:"A: The weather was nice this morning.\nB: Yes, but it started to rain at noon.\nA: That's too bad!",funFact:"It started to rain. Passé composé = specific moment. Contrast il pleuvait."},
        {type:"mc",q:"'Elle ___ triste.' (describing her state) Which tense?",opts:["Était","A été","Est","Sera"],ans:"Était",hint:"Describing how someone felt = state = background tense."},
        {type:"fb",opts:["était","a été","est","sera"],hint:"It was ten o'clock. Telling time in the past = state.",s:"Il {1} dix heures quand je suis arrivé. (to be, time)",a:"était"},
        {type:"mc",q:"Which is a STATE (imparfait)?",opts:["J'ai mangé une pomme","J'avais soif","Je suis parti à midi","J'ai trouvé mes clés"],ans:"J'avais soif",hint:"Being thirsty is not an action. It describes how you felt."},
        {type:"fb",opts:["étions","avons été","sommes","serons"],hint:"We were happy to see you. Emotional state = background.",s:"Nous {1} contents de te voir. (to be, state)",a:"étions"},
        {type:"match",pairs:[{trg:"J'ai mangé",src:"ACTION (PC)"},{trg:"J'avais faim",src:"STATE (imparfait)"},{trg:"Elle est partie",src:"ACTION (PC)"},{trg:"Il faisait froid",src:"STATE (imparfait)"}]},
        {type:"mc",q:"'Il ___ 20 ans quand il ___ en France.' (age + arrived)",opts:["avait / arrivait","a eu / arrivait","avait / est arrivé","a eu / est arrivé"],ans:"avait / est arrivé",hint:"Age = description (background tense). Arriving = event (completed)."},
        {type:"fb",opts:["avais","ai eu","ai","aurai"],hint:"I was 15 in 2010. Age = state = background tense.",s:"J'{1} 15 ans en 2010. (to have, age)",a:"avais"},
        {type:"mc",q:"Weather in the past is typically:",opts:["Passé composé","Conditional","Present","Imparfait"],ans:"Imparfait",hint:"Weather sets the scene. It describes what conditions WERE like."},
        {type:"fb",opts:["avait","a eu","a","aura"],hint:"She had blue eyes. Physical description = state.",s:"Elle {1} les yeux bleus et les cheveux blonds. (to have, description)",a:"avait"},
        {type:"match",pairs:[{trg:"Il faisait beau",src:"weather (imparfait)"},{trg:"J'avais 10 ans",src:"age (imparfait)"},{trg:"Elle a téléphoné",src:"action (PC)"},{trg:"Il était minuit",src:"time (imparfait)"}]},
        {type:"mc",q:"'Le restaurant ___ fermé.' (description of state)",opts:["Était","A été","Est","Sera"],ans:"Était",hint:"The restaurant's state of being closed = background."},
        {type:"fb",opts:["avaient","ont eu","ont","auront"],hint:"They had a lot of work. Describing the situation = state.",s:"Ils {1} beaucoup de travail ce jour-là. (to have, state)",a:"avaient"},
        {type:"mc",q:"Sort: 'J'ai acheté un gâteau parce que j'avais faim.'",opts:["Both PC","PC then imparfait","Both imparfait","Imparfait then PC"],ans:"PC then imparfait",hint:"Bought (event) + was hungry (state explaining why)."}
  ]},
  {id:"fre12l3",title:"Raconter une histoire",icon:"📖",xp:15,board:true,steps:[
        {type:"intro",title:"Telling stories in French",desc:"French storytelling naturally combines both tenses. The imparfait sets the scene, the passé composé moves the story forward. Practice building narratives.",goals:["Build a narrative with both tenses","Set scenes with imparfait","Move action forward with PC"]},
        {type:"tip",title:"Story structure",text:"A French story follows a pattern:\n\n1. SETTING (imparfait):\nC'était un samedi. Il faisait beau.\nLes gens se promenaient.\n\n2. EVENT (passé composé):\nSoudain, un chien a traversé la rue.\n\n3. REACTION (both):\nJ'ai eu peur (event) parce qu'il était\nénorme (description).\n\n4. RESULT (passé composé):\nFinalement, le chien est parti."},
        {type:"teach",trg:"C'était un beau jour d'été.",src:"It was a beautiful summer day.",pos:"intj",gender:null,phonetic:"say-TAY uhn boh zhoor day-TAY",note:"Classic story opening.\nC'était = it was (imparfait of être).\nSets the scene for the story.",example:"A: Raconte-moi tes vacances!\nB: C'était un beau jour d'été. Le soleil brillait.\nA: Ça commence bien!",exampleSrc:"A: Tell me about your vacation!\nB: It was a beautiful summer day. The sun was shining.\nA: Good start!",funFact:"It was a beautiful summer day. Imperfect + setting description. Classic narrative opener."},
        {type:"teach",trg:"Tout le monde s'amusait.",src:"Everyone was having fun.",pos:"intj",gender:null,phonetic:"too luh MOHND sah-mew-ZAY",note:"S'amuser = to have fun.\nImparfait because it describes the scene.\nTout le monde = everyone (takes il/elle form).",example:"A: Comment était la fête?\nB: Tout le monde s'amusait.\nA: Et toi aussi?\nB: Oui, je dansais et je chantais!",exampleSrc:"A: How was the party?\nB: Everyone was having fun.\nA: You too?\nB: Yes, I was dancing and singing!",funFact:"Everyone was having fun. Imperfect of s'amuser. 'Tout le monde' = everyone."},
        {type:"teach",trg:"Finalement, tout s'est bien terminé.",src:"Finally, everything ended well.",pos:"intj",gender:null,phonetic:"fee-nahl-MAHN too say bee-EN tair-mee-NAY",note:"Finalement = finally (story conclusion).\nSe terminer = to end (reflexive).\nPC because it's the concluding event.",example:"A: Et après l'accident?\nB: Les pompiers sont arrivés vite.\nA: Finalement, tout s'est bien terminé?",exampleSrc:"A: And after the accident?\nB: The firefighters arrived quickly.\nA: In the end, everything ended well?",funFact:"Finally, everything ended well. Narrative closer with reflexive verb."},
        {type:"mc",q:"A story opening like 'C'était dimanche. Il pleuvait.' uses:",opts:["Imparfait","Passé composé","Both","Neither"],ans:"Imparfait",hint:"Scene-setting at the start of a story uses the background tense."},
        {type:"fb",opts:["était","a été","est","sera"],hint:"It was a dark and cold night. Classic scene-setting opening.",s:"C'{1} une nuit sombre et froide. (to be, setting)",a:"était"},
        {type:"mc",q:"Which sentence moves the story FORWARD?",opts:["Il faisait beau ce matin, comme toujours","Soudain, le téléphone a sonné","Les oiseaux chantaient près de la fenêtre","Elle portait une robe rouge très élégante"],ans:"Soudain, le téléphone a sonné",hint:"Which one is an event that changes the situation?"},
        {type:"drag_fill",hint:"Children were playing (scene) when father arrived (event).",s:"Les enfants {1} dans le jardin quand le père {2} arrivé. (to play / to be, PC)",blanks:{"1":"jouaient","2":"est"},pool:["jouaient","ont joué","est","a"]},
        {type:"match",pairs:[{trg:"Il faisait beau",src:"scene (imparfait)"},{trg:"Un homme a crié",src:"event (PC)"},{trg:"Les gens marchaient",src:"scene (imparfait)"},{trg:"Elle a trouvé un chat",src:"event (PC)"}]},
        {type:"mc",q:"In 'J'avais peur parce que la maison était vide', both verbs are imparfait because:",opts:["Both are one-time past events","Both are habitual past actions","Both describe states/feelings","Both refer to future hypotheses"],ans:"Both describe states/feelings",hint:"Fear = feeling. Empty house = description. ___ are ___."},
        {type:"fb",opts:["est entré","entrait","entre","entrera"],hint:"Suddenly, a man entered. Sudden event in a story.",s:"Soudain, un homme {1} dans le restaurant. (to enter, PC)",a:"est entré"},
        {type:"mc",q:"Put in order: 'Il ___ (pleuvoir). J'___ (oublier) mon parapluie.'",opts:["a plu / ai oublié","a plu / oubliais","pleuvait / oubliais","pleuvait / ai oublié"],ans:"pleuvait / ai oublié",hint:"Rain was happening (scene) + I forgot (realized, specific event)."},
        {type:"fb",opts:["dansait","a dansé","danse","dansera"],hint:"Everyone was dancing when the music stopped. Ongoing scene.",s:"Tout le monde {1} quand la musique s'est arrêtée. (to dance)",a:"dansait"},
        {type:"match",pairs:[{trg:"C'était samedi",src:"setting"},{trg:"Soudain, un bruit",src:"disruption"},{trg:"J'ai eu peur",src:"reaction"},{trg:"Finalement, tout va bien",src:"conclusion"}]},
        {type:"mc",q:"'Quand je suis sorti, il ne pleuvait plus.' The imparfait here describes:",opts:["The weather condition at that moment","My deliberate action of going out","A future weather forecast","A completed one-time rain event"],ans:"The weather condition at that moment",hint:"What was the ___ doing at the ___ of going out?"},
        {type:"drag_fill",hint:"She was singing (scene) when someone knocked (event).",s:"Elle {1} une chanson quand quelqu'un {2} frappé à la porte. (to sing / to have, PC)",blanks:{"1":"chantait","2":"a"},pool:["chantait","a chanté","a","est"]},
        {type:"mc",q:"A good French story alternates between:",opts:["Only passé composé","Imparfait scenes and PC events","Only imparfait","Present and future"],ans:"Imparfait scenes and PC events",hint:"Background + ___ = natural storytelling rhythm."}
  ]},
  {id:"fre12l4",title:"Actions interrompues",icon:"✂️",xp:15,board:true,steps:[
        {type:"intro",title:"Interrupted actions",desc:"One of the most common patterns: an ongoing action (imparfait) gets interrupted by a sudden event (passé composé). Master the 'quand' and 'pendant que' patterns.",goals:["Use quand + PC for interruptions","Use pendant que + imparfait for background","Combine interrupted action patterns fluently"]},
        {type:"tip",title:"Interruption patterns",text:"Pattern 1: QUAND interruption\nJe dormais QUAND le réveil a sonné.\n(ongoing + WHEN + event)\n\nPattern 2: PENDANT QUE background\nPendant que je cuisinais, il a téléphoné.\n(WHILE + ongoing + event)\n\nPattern 3: Double background\nPendant que je lisais, il regardait la télé.\n(WHILE + ongoing + ongoing)\nBoth imparfait = two simultaneous states."},
        {type:"teach",trg:"Je cuisinais quand il est rentré.",src:"I was cooking when he came home.",pos:"verb",gender:null,phonetic:"zhuh kwee-zee-NAY kahn eel ay rahn-TRAY",note:"Classic interruption:\nOngoing (cuisinais) + quand + event (est rentré).\nCuisinais = imparfait of cuisiner.",example:"A: Tu faisais quoi quand Pierre est rentré?\nB: Je cuisinais quand il est rentré.\nA: Il t'a aidé?",exampleSrc:"A: What were you doing when Pierre came home?\nB: I was cooking when he came home.\nA: Did he help you?",funFact:"I was cooking when he came home. Same pattern. Core French narrative."},
        {type:"teach",trg:"Pendant que nous mangions, il a commencé à neiger.",src:"While we were eating, it started to snow.",pos:"intj",gender:null,phonetic:"pahn-DAHN kuh noo mahn-ZHEE-ON",note:"Pendant que + imparfait = while.\nMangions = imparfait of manger (nous).\nThe snow starting = sudden event (PC).",example:"A: Il a neigé hier?\nB: Oui! Pendant que nous mangions, il a commencé à neiger.\nA: C'était beau?",exampleSrc:"A: Did it snow yesterday?\nB: Yes! While we were eating, it started to snow.\nA: Was it beautiful?",funFact:"While we were eating, it started to snow. Imperfect + passé composé. Complete scene."},
        {type:"mc",q:"'Je ___ quand quelqu'un a frappé.' (to read)",opts:["je lisais","j'ai lu","je lis","je lirai"],ans:"je lisais",hint:"I was reading (ongoing) when someone knocked (event)."},
        {type:"fb",opts:["attendait","a attendu","attend","attendra"],hint:"She was waiting when the bus arrived. Ongoing action interrupted.",s:"Elle {1} quand le bus est arrivé. (to wait)",a:"attendait"},
        {type:"mc",q:"In 'Pendant que tu dormais, j'ai fait les courses', who did the event?",opts:["Tu","Je","Both","Neither"],ans:"Je",hint:"J'ai fait (PC) = the event. Tu dormais = the background."},
        {type:"fb",opts:["travaillait","a travaillé","travaille","travaillera"],hint:"While he was working, she prepared the meal. Ongoing background.",s:"Pendant qu'il {1}, elle a préparé le repas. (to work)",a:"travaillait"},
        {type:"match",pairs:[
          {trg:"Je dormais",src:"ongoing (imparfait)"},
          {trg:"le téléphone a sonné",src:"interruption (PC)"},
          {trg:"Pendant que tu lisais",src:"ongoing background"},
          {trg:"j'ai fait le ménage",src:"event during it"}
        ]},
        {type:"mc",q:"'Pendant que je lisais, il lisait aussi.' Both imparfait because:",opts:["Both are interrupted mid-action","Both are single events","Both are simultaneous states","One sudden action interrupts the other"],ans:"Both are simultaneous states",hint:"Two people doing things at the same time = two backgrounds."},
        {type:"fb",opts:["douchais","suis douché","douche","doucherai"],hint:"I was showering when I heard a noise. Se doucher = reflexive.",s:"Je me {1} quand j'ai entendu un bruit. (to shower, imparfait)",a:"douchais"},
        {type:"mc",q:"Which is correct for interrupted action?",opts:["J'ai mangé quand il arrivait","Je mangeais quand il arrivait","J'ai mangé quand il est arrivé","Je mangeais quand il est arrivé"],ans:"Je mangeais quand il est arrivé",hint:"Ongoing (eating) interrupted by event (arrival)."},
        {type:"fb",opts:["parlaient","ont parlé","parlent","parleront"],hint:"The students were talking when the teacher entered. Ongoing scene.",s:"Les élèves {1} quand le professeur est entré. (to talk)",a:"parlaient"},
        {type:"match",pairs:[
          {trg:"quand + PC",src:"when (interruption)"},
          {trg:"pendant que + imparfait",src:"while (background)"},
          {trg:"soudain + PC",src:"suddenly (event)"},
          {trg:"imparfait + imparfait",src:"two simultaneous states"}
        ]},
        {type:"mc",q:"'Il ___ le journal quand sa femme est rentrée.'",opts:["il lisait","il a lu","il lit","il lira"],ans:"il lisait",hint:"He was reading (ongoing) when his wife came home (event)."},
        {type:"fb",opts:["roulions","avons roulé","roulons","roulerons"],hint:"While we were driving, it started to rain. Nous = -ions.",s:"Pendant que nous {1} en voiture, il a commencé à pleuvoir. (to drive)",a:"roulions"},
        {type:"mc",q:"Double background: 'Il ___ et elle ___.' (to sleep / to read)",opts:["a dormi / a lu","dormait / lisait","a dormi / lisait","dormait / a lu"],ans:"dormait / lisait",hint:"Two simultaneous ongoing states = both use the background tense."},
        {type:"fb",opts:["faisais","ai fait","fais","ferai"],hint:"I was doing the dishes when the glass broke. Ongoing interrupted.",s:"Je {1} la vaisselle quand le verre s'est cassé. (to do)",a:"faisais"}
  ]},
  {id:"fre12l5",title:"Raisons et émotions",icon:"💭",xp:15,board:true,steps:[
        {type:"intro",title:"Reasons and emotions in the past",desc:"When explaining WHY something happened, the reason is usually imparfait (a state) and the result is passé composé (an action). Emotions and mental states always use imparfait.",goals:["Use imparfait for reasons and feelings","Use PC for resulting actions","Build cause-effect sentences"]},
        {type:"tip",title:"Because + state",text:"The pattern: ACTION (PC) + parce que/car + STATE (imparfait)\n\nJ'ai mis un pull parce qu'il faisait froid.\n(I put on a sweater because it was cold.)\n\nElle a pleuré parce qu'elle était triste.\n(She cried because she was sad.)\n\nThe action HAPPENED (PC).\nThe reason EXISTED as a state (imparfait)."},
        {type:"teach",trg:"J'ai pris un taxi parce que j'étais en retard.",src:"I took a taxi because I was late.",pos:"intj",gender:null,phonetic:"zhay pree uhn tak-SEE pars kuh zhay-TAY ahn ruh-TAR",note:"Action (j'ai pris = PC) + reason (j'étais = imparfait).\nÊtre en retard = to be late.",example:"A: Tu es venu en taxi?\nB: Oui, j'ai pris un taxi parce que j'étais en retard.\nA: Ça arrive!",exampleSrc:"A: You came by taxi?\nB: Yes, I took a taxi because I was late.\nA: It happens!",funFact:"I took a taxi because I was late. Passé composé + imperfect. Action + reason."},
        {type:"teach",trg:"Elle était contente parce qu'elle a réussi.",src:"She was happy because she passed.",pos:"verb",gender:null,phonetic:"el ay-TAY kohn-TAHNT pars kel ah ray-ew-SEE",note:"Sometimes the state (contente) is the result\nof an event (a réussi).\nBoth patterns exist in cause-effect.",example:"A: Marie a l'air contente!\nB: Oui, elle était contente parce qu'elle a réussi son examen.\nA: Bravo!",exampleSrc:"A: Marie looks happy!\nB: Yes, she was happy because she passed her exam.\nA: Well done!",funFact:"She was happy because she succeeded. Mixes imperfect + passé composé."},
        {type:"teach",trg:"J'avais peur.",src:"I was afraid.",pos:"intj",gender:null,phonetic:"zhah-VAY puhr",note:"Avoir peur = to be afraid.\nEmotions/feelings = imparfait.\nJ'avais = imparfait of avoir.",example:"A: Tu n'es pas monté dans le manège?\nB: Non, j'avais trop peur.\nA: Ce n'est pas grave!",exampleSrc:"A: You didn't go on the ride?\nB: No, I was too scared.\nA: It's not a big deal!",funFact:"I was afraid. Avoir peur (to have fear) + imperfect = background emotional state."},
        {type:"mc",q:"'J'ai mangé parce que j'___ faim.' Which tense for the reason?",opts:["Avais","Ai eu","Ai","Aurai"],ans:"Avais",hint:"Hunger was the existing state (background) that caused the action."},
        {type:"fb",opts:["était","a été","est","sera"],hint:"He was tired (state), so he went to bed (action).",s:"Il {1} fatigué, alors il s'est couché. (to be, reason)",a:"était"},
        {type:"mc",q:"Which sentence correctly links action + reason?",opts:["J'ai couru parce que j'ai eu peur","J'ai couru parce que j'avais peur","Je courais parce que j'avais peur","Je courais parce que j'ai eu peur"],ans:"J'ai couru parce que j'avais peur",hint:"Running = specific action (PC). Being afraid = state (background)."},
        {type:"fb",opts:["étions","avons été","sommes","serons"],hint:"We were happy when he announced the news. Emotional state.",s:"Nous {1} contents quand il a annoncé la nouvelle. (to be, emotion)",a:"étions"},
        {type:"match",pairs:[{trg:"j'ai pleuré",src:"ACTION (PC)"},{trg:"j'étais triste",src:"REASON/STATE (imparfait)"},{trg:"elle a ri",src:"ACTION (PC)"},{trg:"c'était drôle",src:"REASON/STATE (imparfait)"}]},
        {type:"mc",q:"'Elle a acheté un manteau parce qu'elle ___ froid.'",opts:["A eu","A","Avait","Aura"],ans:"Avait",hint:"She was cold (existing state) = reason for buying."},
        {type:"fb",opts:["n'étais","n'ai été","ne suis","ne serai"],hint:"I was not happy when he said that. Emotional state.",s:"Je ne {1} pas contente quand il a dit ça. (to be, emotion)",a:"n'étais"},
        {type:"mc",q:"Mental states like 'savoir', 'croire', 'penser' in the past are usually:",opts:["Passé composé","Future","Present","Imparfait"],ans:"Imparfait",hint:"Knowing, believing, thinking = ongoing mental states."},
        {type:"fb",opts:["savait","a su","sait","saura"],hint:"He didn't know it was so far. Knowledge = mental state.",s:"Il ne {1} pas que c'était si loin. (to know, mental state)",a:"savait"},
        {type:"match",pairs:[{trg:"j'avais faim",src:"→ j'ai mangé"},{trg:"il faisait froid",src:"→ j'ai mis un pull"},{trg:"elle était malade",src:"→ elle est restée"},{trg:"nous étions fatigués",src:"→ nous avons dormi"}]},
        {type:"mc",q:"'Il ___ qu'elle ___ à Paris.' (to think / to live)",opts:["pensait / habitait","a pensé / a habité","pensait / a habité","a pensé / habitait"],ans:"pensait / habitait",hint:"Both are states: he thought (mental state) she lived (ongoing)."},
        {type:"drag_fill",hint:"They didn't go (event) because they didn't have money (state).",s:"Ils ne {1} pas au restaurant parce qu'ils n'{2} pas d'argent. (to go / to have)",blanks:{"1":"sont allés","2":"avaient"},pool:["sont allés","allaient","avaient","ont eu"]},
        {type:"mc",q:"After learning reasons/emotions: states explain ___, events show ___.",opts:["What / why","Why / what","How / when","When / how"],ans:"Why / what",hint:"States tell you ___ (reason). Events tell you WHAT happened."}
  ]},
  {id:"fre12l6",title:"Changement d'état",icon:"🔄",xp:15,board:true,steps:[
        {type:"intro",title:"When states CHANGE",desc:"Some verbs change meaning depending on the tense! Savoir, connaître, pouvoir, and vouloir have different nuances in PC vs imparfait. PC = the moment of change.",goals:["Understand meaning shifts by tense","Use savoir/connaître correctly in both tenses","Distinguish ongoing states from sudden realizations"]},
        {type:"tip",title:"Meaning shifts",text:"Some verbs change nuance by tense:\n\nsavoir:\nimparfait: je savais = I knew (ongoing)\nPC: j'ai su = I found out (moment of learning)\n\nconnaître:\nimparfait: je connaissais = I knew (person)\nPC: j'ai connu = I met (first time)\n\npouvoir:\nimparfait: je pouvais = I could (ability)\nPC: j'ai pu = I managed to (succeeded)\n\nvouloir:\nimparfait: je voulais = I wanted (ongoing)\nPC: j'ai voulu = I decided/tried to"},
        {type:"teach",trg:"J'ai su la vérité.",src:"I found out the truth.",pos:"intj",gender:null,phonetic:"zhay sew lah vay-ree-TAY",note:"Savoir in PC = moment of discovery.\nJ'ai su = I found out / I learned.\nVs je savais = I knew (already).",example:"A: Tu savais qu'il partait?\nB: Non! J'ai su la vérité hier soir.\nA: C'était un choc?",exampleSrc:"A: Did you know he was leaving?\nB: No! I found out the truth last night.\nA: Was it a shock?",funFact:"I learned the truth. Passé composé of savoir (to know) = to find out, learn. Different from imperfect savais (I knew)."},
        {type:"teach",trg:"J'ai connu Marie en 2015.",src:"I met Marie in 2015.",pos:"intj",gender:null,phonetic:"zhay koh-NEW mah-REE",note:"Connaître in PC = to meet (first encounter).\nJ'ai connu = I met.\nVs je connaissais = I knew (familiarity).",example:"A: Tu connais Marie depuis longtemps?\nB: Oui, j'ai connu Marie en 2015.\nA: Dix ans déjà!",exampleSrc:"A: Have you known Marie for a long time?\nB: Yes, I met Marie in 2015.\nA: Ten years already!",funFact:"Cognate with English 'i met marie in 2015.'. Many English words were borrowed from French after 1066."},
        {type:"mc",q:"Savoir in two tenses: ongoing knowing vs. moment of discovery. Which means 'I found out'?",opts:["J'ai su","Je savais","Je sais","Je saurai"],ans:"J'ai su",hint:"One tense describes a state; the other marks a single moment of learning."},
        {type:"fb",opts:["a su","savait","sait","saura"],hint:"She found out the truth yesterday. Moment of learning.",s:"Elle {1} la vérité hier. (savoir = found out, PC)",a:"a su"},
        {type:"mc",q:"'Je connaissais Paul' means:",opts:["I met Paul (first time)","I knew Paul (familiarity)","I will know Paul","I know Paul now"],ans:"I knew Paul (familiarity)",hint:"Background tense = ongoing state of knowing someone."},
        {type:"fb",opts:["avons connu","connaissions","connaissons","connaîtrons"],hint:"We met Pierre at university. First encounter = event.",s:"Nous {1} Pierre à l'université. (connaître = met, PC)",a:"avons connu"},
        {type:"match",pairs:[{trg:"je savais",src:"I knew (ongoing)"},{trg:"j'ai su",src:"I found out"},{trg:"je connaissais",src:"I knew (person)"},{trg:"j'ai connu",src:"I met (first time)"}]},
        {type:"mc",q:"'Il ___ nager' (he could swim, ongoing ability):",opts:["A pu","Peut","Pouvait","Pourra"],ans:"Pouvait",hint:"An ongoing ability = state = background tense."},
        {type:"fb",opts:["ai pu","pouvais","peux","pourrai"],hint:"Finally, I managed to open the door. Success = event.",s:"Finalement, j'{1} ouvrir la porte. (pouvoir = managed to, PC)",a:"ai pu"},
        {type:"mc",q:"Vouloir in two tenses: ongoing desire vs. acted-on desire. Which implies she actually tried to leave?",opts:["Elle voulait","Neither","Both","Elle a voulu"],ans:"Elle a voulu",hint:"When desire moves from state to action, the completed tense is used."},
        {type:"fb",opts:["voulait","a voulu","veut","voudra"],hint:"He wanted to be a doctor. Ongoing childhood dream.",s:"Il {1} être médecin quand il était jeune. (vouloir = wanted, ongoing)",a:"voulait"},
        {type:"match",pairs:[{trg:"je pouvais",src:"I could (ability)"},{trg:"j'ai pu",src:"I managed to"},{trg:"je voulais",src:"I wanted (ongoing)"},{trg:"j'ai voulu",src:"I decided/tried to"}]},
        {type:"mc",q:"'Quand j'ai su la nouvelle, j'étais choqué.' The PC expresses:",opts:["The moment of learning","An ongoing state","A habitual action","A future plan"],ans:"The moment of learning",hint:"Finding out = the instant you learned. State of shock = background."},
        {type:"fb",opts:["savait","a su","sait","saura"],hint:"She didn't know he was married. Ongoing state of not knowing.",s:"Elle ne {1} pas qu'il était marié. (savoir = knew, ongoing)",a:"savait"},
        {type:"mc",q:"Summary: PC of savoir/connaître/pouvoir/vouloir emphasizes:",opts:["The ongoing state","The moment of change","The habitual action","The future possibility"],ans:"The moment of change",hint:"PC captures when the state SHIFTED: found out, met, managed, decided."},
        {type:"drag_fill",hint:"He could drive (ongoing ability) but had never driven in the city.",s:"Il {1} conduire mais il n'{2} jamais conduit en ville. (pouvoir, ongoing / avoir, PC)",blanks:{"1":"pouvait","2":"avait"},pool:["pouvait","a pu","avait","a eu"]}
  ]},
  {id:"fre12l7",title:"Durée et répétition",icon:"🔁",xp:15,board:true,steps:[
        {type:"intro",title:"Duration and repetition",desc:"Pendant + time expression uses passé composé (bounded duration). Habitual time markers use imparfait. Learn to distinguish bounded vs unbounded past.",goals:["Use pendant + PC for bounded duration","Use imparfait for unbounded repetition","Choose tenses for time expressions"]},
        {type:"tip",title:"Bounded vs unbounded",text:"BOUNDED (PC): has a clear endpoint\nJ'ai habité à Paris pendant 5 ans.\n(I lived in Paris for 5 years.)\nJ'ai attendu pendant 2 heures.\n(I waited for 2 hours.)\n\nUNBOUNDED (imparfait): no clear endpoint\nJ'habitais à Paris. (I was living in Paris.)\nJe l'attendais. (I was waiting for him.)\n\nPendant + specific time = bounded (PC).\nNo time limit stated = unbounded (imparfait)."},
        {type:"teach",trg:"J'ai habité à Paris pendant cinq ans.",src:"I lived in Paris for five years.",pos:"intj",gender:null,phonetic:"zhay ah-bee-TAY ah pah-REE pahn-DAHN sank ahn",note:"Pendant + time = bounded duration.\nThe 5 years have a start and end.\nPC because the period is completed.",example:"A: Tu as vécu à Paris?\nB: Oui, j'ai habité à Paris pendant cinq ans.\nA: Tu y retournes parfois?",exampleSrc:"A: Did you live in Paris?\nB: Yes, I lived in Paris for five years.\nA: Do you go back sometimes?",funFact:"I lived in Paris for five years. Passé composé with pendant (for) + duration. Completed event."},
        {type:"teach",trg:"Tous les étés, nous allions à la mer.",src:"Every summer, we used to go to the sea.",pos:"intj",gender:null,phonetic:"too lay zay-TAY nooz ah-lee-ON ah lah MAIR",note:"Tous les + time = repeated habit.\nAllions = imparfait of aller (nous).\nNo specific endpoint = unbounded.",example:"A: Tu aimais la plage quand tu étais petit?\nB: Oui! Tous les étés, nous allions à la mer.\nA: C'étaient de bons souvenirs!",exampleSrc:"A: Did you like the beach when you were little?\nB: Yes! Every summer, we used to go to the sea.\nA: Those were good memories!",funFact:"Every summer, we would go to the sea. Imperfect + tous les + plural. Habitual recurrence."},
        {type:"mc",q:"'J'ai travaillé pendant trois heures.' Why PC?",opts:["It has a specific time boundary","It was habitual","It was ongoing","It was interrupted"],ans:"It has a specific time boundary",hint:"Three hours = bounded period with an endpoint."},
        {type:"fb",opts:["sommes restés","restions","restons","resterons"],hint:"We stayed there for two weeks. Bounded period = completed.",s:"Nous {1} là pendant deux semaines. (to stay, bounded)",a:"sommes restés"},
        {type:"mc",q:"'Tous les jours, elle ___ du piano.' (habitual)",opts:["A joué","Jouait","Joue","Jouera"],ans:"Jouait",hint:"Every day = repeated habit without a stated endpoint."},
        {type:"fb",opts:["allaient","sont allés","vont","iront"],hint:"Every summer, they used to go. Habitual = unbounded.",s:"Chaque été, ils {1} à la campagne. (to go, habitual)",a:"allaient"},
        {type:"match",pairs:[{trg:"pendant 3 ans",src:"bounded → PC"},{trg:"tous les jours",src:"repeated → imparfait"},{trg:"pendant une heure",src:"bounded → PC"},{trg:"chaque matin",src:"repeated → imparfait"}]},
        {type:"mc",q:"'De 2010 à 2015, j'___ en Allemagne.' Bounded period:",opts:["Habitais","Habite","Ai habité","Habiterai"],ans:"Ai habité",hint:"2010 to 2015 = clear start and end = bounded duration."},
        {type:"fb",opts:["allait","est allé","va","ira"],hint:"On Saturdays, we used to go. Regular habit.",s:"Le samedi, on {1} au marché. (to go, habitual)",a:"allait"},
        {type:"mc",q:"Which is UNBOUNDED?",opts:["J'ai vécu là pendant 2 ans","J'ai attendu 30 minutes","Il a plu toute la journée","On allait souvent au cinéma"],ans:"On allait souvent au cinéma",hint:"Often = no specific time limit. A regular occurrence."},
        {type:"fb",opts:["a étudié","étudiait","étudie","étudiera"],hint:"She studied piano for ten years. Bounded with endpoint.",s:"Elle {1} le piano pendant dix ans. (to study, bounded)",a:"a étudié"},
        {type:"match",pairs:[{trg:"souvent",src:"repeated (imparfait)"},{trg:"pendant 6 mois",src:"bounded (PC)"},{trg:"chaque week-end",src:"repeated (imparfait)"},{trg:"de mars à juin",src:"bounded (PC)"}]},
        {type:"mc",q:"'Avant, je ___ beaucoup. Mais l'année dernière, j'___ complètement.' (to smoke / to stop)",opts:["fumais / ai arrêté","ai fumé / arrêtais","fumais / arrêtais","ai fumé / ai arrêté"],ans:"fumais / ai arrêté",hint:"Habitual smoking (no endpoint) vs. the moment of quitting (event)."},
        {type:"fb",opts:["écrivaient","ont écrit","écrivent","écriront"],hint:"In the old days, people used to write letters. Habitual.",s:"Autrefois, les gens {1} des lettres. (to write, habitual past)",a:"écrivaient"},
        {type:"mc",q:"Summary: pendant + specific time →",opts:["Imparfait","Passé composé","Present","Either tense"],ans:"Passé composé",hint:"A specific duration = bounded = completed period."},
        {type:"fb",opts:["faisait","a fait","fait","fera"],hint:"Every Sunday, my grandmother used to make a cake. Habit.",s:"Chaque dimanche, ma grand-mère {1} un gâteau. (to make)",a:"faisait"}
  ]},
  {id:"fre12l8",title:"Pratique complète",icon:"🏆",xp:15,board:true,steps:[
        {type:"intro",title:"Mastering the distinction",desc:"Comprehensive practice combining all the patterns: signal words, actions vs states, storytelling, interrupted actions, reasons, changed states, and duration.",goals:["Choose tenses fluently in any context","Build complex past narratives","Handle tricky cases with confidence"]},
        {type:"tip",title:"Decision flowchart",text:"When choosing PC or imparfait, ask:\n\n1. Is it a STATE? (weather, emotion, description, age, time)\n   YES = imparfait\n\n2. Is it a HABIT with no clear endpoint?\n   YES = imparfait\n\n3. Did it HAPPEN once, at a specific time?\n   YES = passé composé\n\n4. Is it BOUNDED (pendant + time)?\n   YES = passé composé\n\n5. Does the verb CHANGE MEANING? (savoir, connaître...)\n   Ongoing state = imparfait\n   Moment of change = passé composé"},
        {type:"mc",q:"'Hier, il ___ beau et les oiseaux ___.' (weather + description)",opts:["faisait / chantaient","a fait / ont chanté","a fait / chantaient","faisait / ont chanté"],ans:"faisait / chantaient",hint:"Weather + ongoing activity = two background descriptions."},
        {type:"fb",opts:["est entré","entrait","entre","entrera"],hint:"Suddenly = a specific, sudden event. Which tense for events?",s:"Soudain, le chien {1} dans la maison. (to enter, event)",a:"est entré"},
        {type:"mc",q:"'Je ___ un taxi parce que le bus ne ___ pas.' (take / come)",opts:["prenais / est venu","ai pris / venait","ai pris / est venu","prenais / venait"],ans:"ai pris / venait",hint:"Took a taxi (action) because bus wasn't coming (ongoing state/reason)."},
        {type:"drag_fill",hint:"She found out (moment) and was surprised (state).",s:"Elle {1} la nouvelle et elle {2} très surprise. (to learn / to be)",blanks:{"1":"a appris","2":"était"},pool:["a appris","apprenait","était","a été"]},
        {type:"match",pairs:[{trg:"Il pleuvait",src:"background (imparfait)"},{trg:"J'ai pris mon parapluie",src:"action (PC)"},{trg:"J'étais en retard",src:"state (imparfait)"},{trg:"J'ai couru",src:"action (PC)"}]},
        {type:"mc",q:"'Pendant 10 ans, elle ___ professeur.' (bounded career)",opts:["Était","Est","A été","Sera"],ans:"A été",hint:"Ten years = bounded period with start and end."},
        {type:"drag_fill",hint:"I was 18 (age = state) when I entered (event).",s:"Quand j'{1} 18 ans, j'{2} à l'université. (have, age / enter, event)",blanks:{"1":"avais","2":"suis entré"},pool:["avais","ai eu","suis entré","entrais"]},
        {type:"mc",q:"'Avant, il ne ___ pas nager. Un jour, il ___ des cours.'",opts:["pouvait / a pris","a pu / prenait","pouvait / prenait","savait / a pris"],ans:"savait / a pris",hint:"Didn't know how (ongoing) + decided to take lessons (event)."},
        {type:"drag_fill",hint:"Every evening, we used to eat and talk. Two regular habits.",s:"Tous les soirs, nous {1} ensemble et nous {2} de notre journée. (eat / talk, habits)",blanks:{"1":"mangions","2":"parlions"},pool:["mangions","avons mangé","parlions","avons parlé"]},
        {type:"match",pairs:[{trg:"J'ai su",src:"I found out"},{trg:"Je savais",src:"I knew (ongoing)"},{trg:"J'ai connu",src:"I met"},{trg:"Je connaissais",src:"I knew (person)"}]},
        {type:"mc",q:"Complete the story: 'C'___ dimanche. Il ___ beau. J'___ de sortir.'",opts:["était / faisait / ai décidé","a été / a fait / ai décidé","était / faisait / décidais","a été / a fait / décidais"],ans:"était / faisait / ai décidé",hint:"Day + weather = scene setting. Decision = the event."},
        {type:"drag_fill",hint:"Kids were playing (scene) when rain started (sudden event).",s:"Les enfants {1} quand il {2} à pleuvoir. (play, ongoing / start, event)",blanks:{"1":"jouaient","2":"a commencé"},pool:["jouaient","ont joué","a commencé","commençait"]},
        {type:"mc",q:"Which is the trickiest case?",opts:["Weather = imparfait (always)","'J'ai su' = found out (change of state)","Pendant + time = PC (bounded)","Emotions = imparfait (always)"],ans:"'J'ai su' = found out (change of state)",hint:"___ verbs changing meaning in PC is the most nuanced pattern."},
        {type:"drag_fill",hint:"Late (time) + tired (state) + went to bed (action).",s:"Il {1} tard et je {2} fatigué, alors je {3} couché. (be, time / be, state / go, event)",blanks:{"1":"était","2":"étais","3":"me suis"},pool:["était","a été","étais","me suis"]},
        {type:"mc",q:"You've mastered the PC vs imparfait distinction! The key is recognizing:",opts:["Only signal words","Only verb forms","Context: events vs states/backgrounds","Only time expressions"],ans:"Context: events vs states/backgrounds",hint:"It's about understanding what role each verb plays in the story."},
        {type:"drag_fill",hint:"It was the best day (state/description) when I got my diploma (event).",s:"C'{1} le plus beau jour de ma vie quand j'{2} obtenu mon diplôme. (be / have)",blanks:{"1":"était","2":"ai"},pool:["était","a été","ai","avais"]}
  ]},
  {id:"fre12l8b",title:"Les Métiers",icon:"👩‍⚕️",xp:15,board:true,steps:[
        {type:"intro",title:"Les Métiers",desc:"Learn the names of common professions in French with masculine and feminine forms.",goals:["Learn 12 professions with m/f forms","Understand -eur/-euse, -ien/-ienne, -ier/-ière patterns","Talk about jobs and careers"]},
        {type:"teach",trg:"le médecin / la médecin",src:"the doctor",pos:"noun",gender:"m",phonetic:"luh med-SAN / la med-SAN",note:"le/la médecin: same form for m/f.\nNo article with être + profession:\nje suis médecin (not je suis un médecin).",example:"A: Quel est ton métier ?\nB: Je suis médecin.\nA: Dans un hôpital ?\nB: Oui, à l'hôpital central.",exampleSrc:"A: What is your profession?\nB: I am a doctor.\nA: In a hospital?\nB: Yes, at the central hospital.",funFact:"Doctor (m/f). Older form kept 'le' for both; modern form: 'la médecin' feminine."},
        {type:"teach",trg:"le professeur / la professeure",src:"the teacher/professor",pos:"noun",gender:"m",phonetic:"luh pro-feh-SUR / la pro-feh-SUR",note:"le professeur / la professeure.\nInformal: le/la prof.",example:"A: Madame Dupont est professeure ?\nB: Oui, elle enseigne le français.\nA: Elle est stricte ?\nB: Non, elle est très gentille.",exampleSrc:"A: Is Mrs. Dupont a teacher?\nB: Yes, she teaches French.\nA: Is she strict?\nB: No, she is very kind.",funFact:"Professor/teacher (m/f). Feminine added 'e' in 2000s. Old form invariable."},
        {type:"teach",trg:"l'infirmier / l'infirmière",src:"the nurse (m/f)",pos:"intj",gender:null,phonetic:"lan-feer-MYAY / lan-feer-MYEHR",note:"l'infirmier (m) / l'infirmière (f).\nPattern: -ier/-ière.",example:"A: Mon frère est infirmier.\nB: Dans quel hôpital ?\nA: À l'hôpital Saint-Louis.\nB: C'est un métier admirable.",exampleSrc:"A: My brother is a nurse.\nB: In which hospital?\nA: At Saint-Louis hospital.\nB: It is an admirable profession.",funFact:"Nurse (m/f). Article l' elided before vowel. Masculine -ier/-ière pattern."},
        {type:"teach",trg:"le policier / la policière",src:"the police officer (m/f)",pos:"noun",gender:"m",phonetic:"luh po-lee-SYAY / la po-lee-SYEHR",note:"le policier / la policière.\nAlso: l'agent de police (m/f).",example:"A: Il y a un policier devant l'école.\nB: Oui, c'est pour la sécurité.\nA: Ma cousine est policière.\nB: C'est un travail difficile.",exampleSrc:"A: There is a police officer in front of the school.\nB: Yes, it is for safety.\nA: My cousin is a police officer.\nB: It is a difficult job.",funFact:"Police officer (m/f). Feminine adds -ière. Gender-paired profession."},
        {type:"teach",trg:"le pompier / la pompière",src:"the firefighter (m/f)",pos:"noun",gender:"m",phonetic:"luh pom-PYAY / la pom-PYEHR",note:"le pompier / la pompière.\nPattern: -ier/-ière.",example:"A: Les pompiers arrivent !\nB: Oui, il y a un incendie.\nA: Ils sont très courageux.\nB: Ma soeur est pompière aussi.",exampleSrc:"A: The firefighters are coming!\nB: Yes, there is a fire.\nA: They are very brave.\nB: My sister is a firefighter too.",funFact:"Firefighter (m/f). From 'pompe' (pump). Emergency vocabulary."},
        {type:"teach",trg:"le cuisinier / la cuisinière",src:"the chef/cook (m/f)",pos:"noun",gender:"m",phonetic:"luh kwee-zee-NYAY / la kwee-zee-NYEHR",note:"le cuisinier / la cuisinière.\nPattern: -ier/-ière.",example:"A: Qui fait la cuisine ici ?\nB: C'est le cuisinier du restaurant.\nA: Il cuisine bien ?\nB: Oui, c'est un excellent cuisinier.",exampleSrc:"A: Who cooks here?\nB: It is the restaurant chef.\nA: Does he cook well?\nB: Yes, he is an excellent chef.",funFact:"Cook (m/f). From 'cuisine' + -ier. Same Latin root as English 'kitchen.'"},
        {type:"teach",trg:"l'ingénieur / l'ingénieure",src:"the engineer (m/f)",pos:"intj",gender:null,phonetic:"lan-zhay-NYUR / lan-zhay-NYUR",note:"l'ingénieur (m) / l'ingénieure (f).\nSame pronunciation for both.",example:"A: Tu es ingénieure ?\nB: Oui, en informatique.\nA: C'est intéressant ?\nB: Oui, très intéressant !",exampleSrc:"A: Are you an engineer?\nB: Yes, in computer science.\nA: Is it interesting?\nB: Yes, very interesting!",funFact:"Engineer (m/f). Recent feminization: ingénieure is modern addition to cover women."},
        {type:"teach",trg:"l'avocat / l'avocate",src:"the lawyer (m/f)",pos:"intj",gender:null,phonetic:"la-vo-KA / la-vo-KAT",note:"l'avocat (m) / l'avocate (f).\nAlso means avocado (the fruit)!",example:"A: Mon père est avocat.\nB: Il travaille dans quel domaine ?\nA: Le droit de la famille.\nB: C'est un domaine important.",exampleSrc:"A: My father is a lawyer.\nB: In which field does he work?\nA: Family law.\nB: It is an important field.",funFact:"Lawyer / avocado. Dual meaning! Context decides. Feminine avocate is unambiguous (no avocat-feminine of fruit)."},
        {type:"teach",trg:"le chauffeur / la chauffeuse",src:"the driver (m/f)",pos:"noun",gender:"m",phonetic:"luh sho-FUR / la sho-FUZ",note:"le chauffeur / la chauffeuse.\nPattern: -eur/-euse.",example:"A: Le chauffeur de bus est gentil.\nB: Oui, il dit toujours bonjour.\nA: Ma tante est chauffeuse de taxi.\nB: Elle connaît bien la ville.",exampleSrc:"A: The bus driver is kind.\nB: Yes, he always says hello.\nA: My aunt is a taxi driver.\nB: She knows the city well.",funFact:"Driver (m/f). From 'chauffer' (to heat). Originally 'stoker' of steam cars."},
        {type:"teach",trg:"le/la journaliste",src:"the journalist",pos:"intj",gender:null,phonetic:"luh/la zhoor-na-LEEST",note:"le/la journaliste: same form m/f.\nOnly the article changes.",example:"A: Cette journaliste parle bien.\nB: Oui, elle travaille à la télévision.\nA: Mon ami est journaliste aussi.\nB: Pour un journal ou la radio ?",exampleSrc:"A: This journalist speaks well.\nB: Yes, she works on television.\nA: My friend is a journalist too.\nB: For a newspaper or the radio?",funFact:"Journalist. -iste endings invariable in gender. Only article changes. French profession vocabulary."},
        {type:"teach",trg:"le pharmacien / la pharmacienne",src:"the pharmacist (m/f)",pos:"noun",gender:"m",phonetic:"luh far-ma-SYAN / la far-ma-SYEN",note:"le pharmacien / la pharmacienne.\nPattern: -ien/-ienne.",example:"A: Je vais chez le pharmacien.\nB: Tu as besoin de médicaments ?\nA: Oui, pour mon rhume.\nB: La pharmacienne va te conseiller.",exampleSrc:"A: I am going to the pharmacist.\nB: Do you need medicine?\nA: Yes, for my cold.\nB: The pharmacist will advise you.",funFact:"Pharmacist (m/f). Greek 'pharmakon' (drug/poison). Feminine doubles n."},
        {type:"teach",trg:"le chanteur / la chanteuse",src:"the singer (m/f)",pos:"noun",gender:"m",phonetic:"luh shon-TUR / la shon-TUZ",note:"le chanteur / la chanteuse.\nPattern: -eur/-euse.",example:"A: Tu connais cette chanteuse ?\nB: Oui, elle chante très bien.\nA: Mon frère est chanteur.\nB: Il chante quel genre de musique ?",exampleSrc:"A: Do you know this singer?\nB: Yes, she sings very well.\nA: My brother is a singer.\nB: What genre of music does he sing?",funFact:"Singer (m/f). From 'chanter' (to sing). -eur/-euse pattern for agent nouns."},
        {type:"tip",title:"Les terminaisons des métiers",deepDive:{
          title:"More patterns",
          text:"Some modern French allows adding -e to traditionally invariable nouns: professeur becomes professeure, ingénieur becomes ingénieure. This is especially common in Quebec French and increasingly accepted in France. Words ending in -iste (journaliste, dentiste) are always the same for both genders."
        },text:"French profession endings follow patterns for masculine/feminine:\n-eur / -euse: chanteur/chanteuse, chauffeur/chauffeuse\n-ien / -ienne: pharmacien/pharmacienne\n-ier / -ière: infirmier/infirmière, pompier/pompière\nSome are identical: médecin, journaliste."},
        {type:"mc",q:"What is the feminine form of 'le chanteur'?",opts:["la chanteuse","la chanteresse","la chantrice","la chanteure"],ans:"la chanteuse",hint:"The -eur ending changes to a pattern with -euse."},
        {type:"mc",q:"Which profession uses the same form for masculine and feminine?",opts:["le cuisinier","le médecin","le pompier","le chanteur"],ans:"le médecin",hint:"This health professional keeps the same spelling regardless of gender."},
        {type:"fb",opts:["infirmière","pompière","cuisinière","policière"],hint:"This person cares for patients in a hospital setting.",s:"Ma soeur est {1}, elle travaille à l'hôpital.",a:["infirmière"]},
        {type:"fb",opts:["cuisinier","chauffeur","pharmacien","chanteur"],hint:"This person works in a kitchen preparing food professionally.",s:"Le {1} prépare de délicieux plats au restaurant.",a:["cuisinier"]},
        {type:"match",pairs:[{trg:"le chauffeur",src:"the driver"},{trg:"l'avocat",src:"the lawyer"},{trg:"le pompier",src:"the firefighter"},{trg:"le pharmacien",src:"the pharmacist"},{trg:"le journaliste",src:"the journalist"}]},
        {type:"mc",q:"Comment dit-on 'the female police officer' en français ?",opts:["la policiste","la policieure","la policière","la policeuse"],ans:"la policière",hint:"The -ier ending changes following a common feminine pattern."},
        {type:"fb",opts:["chauffeur","pompier","cuisinier","chanteur"],hint:"This person's job is to drive vehicles for passengers.",s:"Mon voisin est {1}, il conduit un taxi toute la journée.",a:["chauffeur"]}
  ]}
, COVERAGE_U12]};
